SELECT pr.id AS id, pr.school_year AS schoolYear, ss.id AS semesterId, ss.name AS semesterName, grade.id AS classGroupId, grade.grade_group_name AS classGroupName, cla.id AS classId, cla.class_name AS className, stu.seat_no AS studentClassNumber, stu.id AS studentId, stu.chinese_name AS studentName, pr.registration_date AS registrationDate, pr.lesson_period_id AS lessonPeriodId, # l.name AS lessonPeriod, pr.registration_id AS registrationId, pr.registration_content AS registrationContent, pr.registrant AS registrant FROM patrol_registration pr LEFT JOIN student_info stu ON stu.id = pr.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_semester ss on pr.semester_id = ss.id # LEFT JOIN lesson l on pr.lesson_period_id = l.id WHERE pr.deleted = 0
AND pr.school_id = ${reqModel.schoolId}
AND pr.school_year = #{reqModel.schoolYear}
AND pr.semester_id = ${reqModel.semesterId}
AND pr.class_id = ${reqModel.classId}
AND pr.student_id = ${reqModel.studentId}
AND pr.registration_date >= #{reqModel.startDate}
AND pr.registration_date <= #{reqModel.endDate}
AND pr.class_id IN
#{item}
ORDER BY pr.create_time desc
